#include <bits/stdc++.h>
using namespace std;
int n,q,a[300005],id[300005];
long long p[300005];
int main(){
    //p[i]=开头为i，长度为1的排名
    //id[i]为b[i]
    cin>>n>>q;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        id[a[i]]=i;
    }
    long long sum=1;
    for(int i=1;i<=n;i++){
        p[i]=sum;
        sum+=n-id[i]+1;
    }
    while(q--){
        long long t;
        cin>>t;
        int l=1,r=n;
        while(l<r){
            int mid=(l+r+1)/2;
            if(p[mid]<=t)
                l=mid;
            else
                r=mid-1;
        }
        cout<<id[l]<<' '<<id[l]+t-p[l]<<'\n';
    }
    return 0;
}
